<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        :root {
            --bg-color: #300a24;
            --taskbar-color: rgba(0, 0, 0, 0.6);
            --win-bg: #2c2c2c;
            --win-header: #3c3c3c;
            --text-color: #ffffff;
            --accent-color: #e95420;
            --border-color: #444;
        }

        * { box-sizing: border-box; }
        body, html { 
            margin: 0; padding: 0; 
            width: 100%; height: 100%; 
            font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
            overflow: hidden;
            background-color: var(--bg-color);
        }

        #desktop {
            position: relative;
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #5E2750 0%, #2C041E 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            height: 60px;
            background: var(--taskbar-color);
            backdrop-filter: blur(10px);
            border-radius: 12px;
            display: flex;
            align-items: center;
            padding: 0 15px;
            gap: 15px;
            z-index: 1000;
            border: 1px solid rgba(255,255,255,0.1);
        }

        .launcher {
            width: 40px;
            height: 40px;
            background: #444;
            border-radius: 8px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 20px;
            transition: background 0.2s, transform 0.1s;
            border: none;
        }
        .launcher:hover { background: #666; }
        .launcher:active { transform: scale(0.9); }

        /* Window System */
        .window {
            position: absolute;
            width: 450px;
            height: 320px;
            min-width: 360px;
            min-height: 240px;
            background: var(--win-bg);
            border: 1px solid var(--border-color);
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            border-radius: 8px;
            display: none;
            flex-direction: column;
            z-index: 10;
            color: var(--text-color);
        }

        .win-header {
            height: 35px;
            background: var(--win-header);
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 10px;
            border-top-left-radius: 8px;
            border-top-right-radius: 8px;
            cursor: default;
            user-select: none;
        }

        .win-title { font-size: 13px; font-weight: bold; }

        .win-close {
            width: 24px;
            height: 24px;
            background: #ff5f56;
            border: none;
            border-radius: 50%;
            cursor: pointer;
            color: white;
            font-weight: bold;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .win-close:hover { background: #ff3b30; }

        .win-body {
            flex: 1;
            overflow: auto;
            position: relative;
            display: flex;
            flex-direction: column;
        }

        /* Files App */
        #files-toolbar {
            background: #333;
            padding: 5px 10px;
            display: flex;
            gap: 10px;
            align-items: center;
            border-bottom: 1px solid var(--border-color);
        }
        #files-path {
            font-size: 12px;
            flex: 1;
            background: #1e1e1e;
            padding: 2px 8px;
            border-radius: 4px;
            color: #ccc;
        }
        #files-up {
            cursor: pointer;
            background: #555;
            border: none;
            color: white;
            padding: 2px 8px;
            border-radius: 4px;
            font-size: 12px;
        }

        #files-list {
            padding: 10px;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
            align-content: start;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            text-align: center;
            cursor: pointer;
            font-size: 12px;
            padding: 5px;
            border-radius: 4px;
        }
        .fs-item:hover { background: rgba(255,255,255,0.1); }
        .fs-icon { font-size: 30px; margin-bottom: 5px; }

        /* Notepad App */
        #notepad-tabs-container {
            display: flex;
            background: #222;
            border-bottom: 1px solid var(--border-color);
            overflow-x: auto;
        }
        .tab {
            padding: 8px 15px;
            cursor: pointer;
            font-size: 12px;
            background: #333;
            border-right: 1px solid var(--border-color);
            user-select: none;
        }
        .tab.active { background: var(--win-bg); border-bottom: 2px solid var(--accent-color); }
        #new-tab {
            padding: 0 15px;
            cursor: pointer;
            background: #444;
            border: none;
            color: white;
            font-weight: bold;
            font-size: 18px;
        }

        #editor {
            width: 100%;
            height: 100%;
            background: var(--win-bg);
            color: #ddd;
            border: none;
            resize: none;
            padding: 15px;
            font-family: 'Courier New', Courier, monospace;
            outline: none;
        }
    </style>
</head>
<body>

<div id="desktop">
    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files" class="launcher" title="Files">📁</button>
        <button id="open-notepad" class="launcher" title="Notepad">📝</button>
    </div>

    <!-- Files Window -->
    <div id="files-window" class="window" style="top: 50px; left: 50px;">
        <div class="win-header">
            <span class="win-title">Files</span>
            <button class="win-close">×</button>
        </div>
        <div class="win-body">
            <div id="files-toolbar">
                <button id="files-up">↑ Up</button>
                <div id="files-path">/</div>
            </div>
            <div id="files-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window" style="top: 100px; left: 150px;">
        <div class="win-header">
            <span class="win-title">Notepad</span>
            <button class="win-close">×</button>
        </div>
        <div class="win-body">
            <div id="notepad-tabs-container">
                <div id="tabs" style="display: flex;"></div>
                <button id="new-tab">+</button>
            </div>
            <textarea id="editor"></textarea>
        </div>
    </div>
</div>

<script>
    /** 
     * WINDOW MANAGEMENT 
     */
    function makeDraggable(win) {
        const header = win.querySelector('.win-header');
        let isDragging = false;
        let offsetX, offsetY;

        header.onmousedown = (e) => {
            isDragging = true;
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            // Bring to front
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 100;
        };

        document.onmousemove = (e) => {
            if (!isDragging) return;
            win.style.left = (e.clientX - offsetX) + 'px';
            win.style.top = (e.clientY - offsetY) + 'px';
        };

        document.onmouseup = () => isDragging = false;
    }

    const filesWin = document.getElementById('files-window');
    const notepadWin = document.getElementById('notepad-window');
    makeDraggable(filesWin);
    makeDraggable(notepadWin);

    document.getElementById('open-files').onclick = () => filesWin.style.display = 'flex';
    document.getElementById('open-notepad').onclick = () => notepadWin.style.display = 'flex';

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.onclick = (e) => {
            e.target.closest('.window').style.display = 'none';
        };
    });

    /** 
     * FILES APP LOGIC 
     */
    const fsData = {
        '/': { type: 'dir', children: ['bin', 'etc', 'home', 'usr', 'var'] },
        '/bin': { type: 'dir', children: ['bash', 'ls', 'grep'] },
        '/etc': { type: 'dir', children: ['passwd', 'hosts', 'network'] },
        '/home': { type: 'dir', children: ['user'] },
        '/home/user': { type: 'dir', children: ['Documents', 'Downloads', 'Pictures', 'todo.txt'] },
        '/home/user/Documents': { type: 'dir', children: ['resume.pdf', 'notes.txt'] },
        '/home/user/Downloads': { type: 'dir', children: ['ubuntu-installer.iso'] },
        '/home/user/Pictures': { type: 'dir', children: ['wallpaper.jpg', 'vacation.png'] },
        '/usr': { type: 'dir', children: ['bin', 'lib', 'share'] },
        '/var': { type: 'dir', children: ['log', 'tmp'] },
        // Files (leaf nodes)
        '/home/user/todo.txt': { type: 'file' },
        '/home/user/Documents/resume.pdf': { type: 'file' },
        '/home/user/Documents/notes.txt': { type: 'file' },
        '/home/user/Downloads/ubuntu-installer.iso': { type: 'file' },
        '/home/user/Pictures/wallpaper.jpg': { type: 'file' },
        '/home/user/Pictures/vacation.png': { type: 'file' },
    };

    let currentPath = '/';

    function renderFiles() {
        const list = document.getElementById('files-list');
        const pathDisplay = document.getElementById('files-path');
        list.innerHTML = '';
        pathDisplay.innerText = currentPath;

        const folder = fsData[currentPath];
        if (!folder || !folder.children) return;

        folder.children.forEach(name => {
            const fullPath = (currentPath === '/' ? '' : currentPath) + '/' + name;
            const item = document.createElement('div');
            item.className = 'fs-item';

            const isDir = fsData[fullPath] && fsData[fullPath].type === 'dir';
            item.innerHTML = `<div class="fs-icon">${isDir ? '📁' : '📄'}</div><div>${name}</div>`;

            item.ondblclick = () => {
                if (isDir) {
                    currentPath = fullPath;
                    renderFiles();
                }
            };
            list.appendChild(item);
        });
    }

    document.getElementById('files-up').onclick = () => {
        if (currentPath === '/') return;
        const parts = currentPath.split('/').filter(p => p);
        parts.pop();
        currentPath = '/' + parts.join('/');
        if (currentPath === '') currentPath = '/';
        renderFiles();
    };

    renderFiles();

    /** 
     * NOTEPAD APP LOGIC 
     */
    let tabs = [];
    let activeTabId = null;

    const tabContainer = document.getElementById('tabs');
    const editor = document.getElementById('editor');

    function saveToStorage() {
        localStorage.setItem('ubuntu_notepad_tabs', JSON.stringify(tabs));
    }

    function loadFromStorage() {
        const saved = localStorage.getItem('ubuntu_notepad_tabs');
        if (saved) {
            tabs = JSON.parse(saved);
            if (tabs.length > 0) {
                activeTabId = tabs[0].id;
            } else {
                createNewTab();
            }
        } else {
            createNewTab();
        }
        renderTabs();
    }

    function createNewTab() {
        const id = Date.now();
        tabs.push({ id, name: `Untitled ${tabs.length + 1}`, content: '' });
        activeTabId = id;
        saveToStorage();
        renderTabs();
    }

    function renderTabs() {
        tabContainer.innerHTML = '';
        tabs.forEach(tab => {
            const el = document.createElement('div');
            el.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            el.innerText = tab.name;
            el.onclick = () => {
                activeTabId = tab.id;
                renderTabs();
                updateEditorContent();
            };
            tabContainer.appendChild(el);
        });
        updateEditorContent();
    }

    function updateEditorContent() {
        const activeTab = tabs.find(t => t.id === activeTabId);
        editor.value = activeTab ? activeTab.content : '';
    }

    editor.oninput = () => {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
            activeTab.content = editor.value;
            saveToStorage();
        }
    };

    document.getElementById('new-tab').onclick = createNewTab;

    loadFromStorage();

</script>
</body>
</html>
